function listPosts(orderBy) {
  // Validate orderBy against allowlist
  const allowedColumns = ["id", "title", "author", "category", "status"];
  const validOrderBy = allowedColumns.includes(orderBy) ? orderBy : "id";

  const result = db.query("listAll", { orderBy: validOrderBy });
