      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#x27;');
  }

  return {
    id: post.id,
    title: htmlEncode(post.title),
    body: htmlEncode(post.body),
    author: post.author,
  };
}

